# Memory Leaking with `Box::leak` in Rust

## Basic Implementation

```rust
use std::collections::HashMap;
use std::sync::OnceLock;

// ============================================================
// Core examples of Box::leak usage
// ============================================================

/// Leaks a value and returns a static reference.
/// The memory lives for the entire program duration.
fn leak_string(s: String) -> &'static str {
    Box::leak(s.into_boxed_str())
}

fn leak_vec<T>(v: Vec<T>) -> &'static [T] {
    Box::leak(v.into_boxed_slice())
}

fn leak_value<T>(value: T) -> &'static T {
    Box::leak(Box::new(value))
}

fn leak_value_mut<T>(value: T) -> &'static mut T {
    Box::leak(Box::new(value))
}

